// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('move screen from menu', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('move screen from menu', async function() {
    // Test name: move screen from menu
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/list-evaluation | 
    await driver.get("http://localhost:4200/user/list-evaluation");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | click | xpath=//div[@id='root']/section/section/header/div/ul/li[4] | 
    await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/header/div/ul/li[4]")).click();

    // 4 | assertText | css=.ant-layout-content > .ant-typography | 部門目標
    assert(await driver.findElement(By.css(".ant-layout-content > .ant-typography")).getText() == "部門目標");
  });
});
